param([Parameter(Mandatory=$true)][string]$InputPath,[string]$ProjectRoot='',[switch]$ValidateOnly,[switch]$AllowTestSource)
$ErrorActionPreference='Stop';if([string]::IsNullOrWhiteSpace($ProjectRoot)){$ProjectRoot=Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)};if(-not(Test-Path -LiteralPath $InputPath)){throw "Input not found: $InputPath"};$required=@('MatchID','LotteryMatchID','MatchNumber','SnapshotTime','Market','Handicap','Selection','Odds','SaleStatus','SourceAgency','SourceReference');$header=(Get-Content -LiteralPath $InputPath -TotalCount 1 -Encoding UTF8)-split',';foreach($c in $required){if($c-notin$header){throw "Missing column: $c"}};$rows=@(Import-Csv -LiteralPath $InputPath -Encoding UTF8);if($rows.Count-eq0){return [pscustomobject]@{Status='VALID_TEMPLATE';Rows=0;Written=$false}|ConvertTo-Json}
$known=[Collections.Generic.HashSet[string]]::new([StringComparer]::Ordinal);Import-Csv (Join-Path $ProjectRoot 'data\standardized\matches_all.csv') -Encoding UTF8|ForEach-Object{[void]$known.Add($_.MatchID)};Import-Csv (Join-Path $ProjectRoot 'data\standardized\fixtures.csv') -Encoding UTF8|ForEach-Object{[void]$known.Add($_.MatchID)};$keys=[Collections.Generic.HashSet[string]]::new([StringComparer]::Ordinal);$dest=Join-Path $ProjectRoot 'data\standardized\jczq_odds.csv';$existing=if(Test-Path $dest){@(Import-Csv $dest -Encoding UTF8)}else{@()};foreach($x in $existing){[void]$keys.Add((@($x.MatchID,$x.SnapshotTime,$x.Market,$x.Handicap,$x.Selection)-join'|'))};$valid=[Collections.Generic.List[object]]::new();$allowedMarkets=@('SPF','RQSPF','BF','JQS','BQC');$allowedStatus=@('OPEN','CLOSED','SUSPENDED');$evidenceMap=@{};$manifest=Join-Path $ProjectRoot 'data\raw\jczq\evidence_manifest.csv';if(Test-Path $manifest){Import-Csv $manifest -Encoding UTF8|ForEach-Object{$evidenceMap[$_.EvidenceID]=$_}}
foreach($r in $rows){$id=$r.MatchID.Trim();if(-not$known.Contains($id)){throw "Unknown MatchID: $id"};$market=$r.Market.Trim().ToUpperInvariant();if($market-notin$allowedMarkets){throw "Invalid market: $market"};$selection=$r.Selection.Trim().ToUpperInvariant();if($r.SaleStatus.Trim().ToUpperInvariant()-notin$allowedStatus){throw 'Invalid SaleStatus'};$dt=[datetimeoffset]::MinValue;if(-not[datetimeoffset]::TryParse($r.SnapshotTime,[Globalization.CultureInfo]::InvariantCulture,[Globalization.DateTimeStyles]::None,[ref]$dt)){throw 'Invalid SnapshotTime'};$odd=0.0;if(-not[double]::TryParse($r.Odds,[Globalization.NumberStyles]::Float,[Globalization.CultureInfo]::InvariantCulture,[ref]$odd)-or$odd-le1){throw 'Odds must be greater than one'};$handicap='';if($market-eq'RQSPF'){$h=0;if(-not[int]::TryParse($r.Handicap,[ref]$h)-or$h-eq0){throw 'RQSPF requires a non-zero integer handicap'};$handicap=$h;if($selection-notin@('H','D','A')){throw 'Invalid RQSPF selection'}}elseif($market-eq'SPF'){if($r.Handicap-ne''-or$selection-notin@('H','D','A')){throw 'Invalid SPF row'}}elseif($market-eq'JQS'){if($selection-notin@('0','1','2','3','4','5','6','7+')){throw 'Invalid JQS selection'}}elseif($market-eq'BQC'){if($selection-notin@('HH','HD','HA','DH','DD','DA','AH','AD','AA')){throw 'Invalid BQC selection'}};if(-not$AllowTestSource-and$r.SourceAgency-ne'CHINA_SPORTS_LOTTERY'){throw 'Non-official source rejected'};if(-not$AllowTestSource){$reference=$r.SourceReference.Trim();if(-not$evidenceMap.ContainsKey($reference)){throw "Unregistered evidence reference: $reference"};$evidence=$evidenceMap[$reference];if([string]::IsNullOrWhiteSpace($evidence.StoredRelativePath)){throw "Evidence artifact path missing: $reference"};$artifact=Join-Path $ProjectRoot ($evidence.StoredRelativePath -replace '/','\');if(-not(Test-Path -LiteralPath $artifact)){throw "Evidence artifact missing: $reference"};if((Get-FileHash -LiteralPath $artifact -Algorithm SHA256).Hash.ToLowerInvariant()-ne$evidence.Sha256.ToLowerInvariant()){throw "Evidence artifact hash mismatch: $reference"}};$key=@($id,$dt.ToString('o'),$market,$handicap,$selection)-join'|';if(-not$keys.Add($key)){throw "Duplicate odds row: $key"};$valid.Add([pscustomobject]@{MatchID=$id;LotteryMatchID=$r.LotteryMatchID.Trim();MatchNumber=$r.MatchNumber.Trim();SnapshotTime=$dt.ToString('o');Market=$market;Handicap=$handicap;Selection=$selection;Odds=$odd;SaleStatus=$r.SaleStatus.Trim().ToUpperInvariant();SourceAgency=$r.SourceAgency.Trim();SourceReference=$r.SourceReference.Trim();ImportedAt=(Get-Date).ToUniversalTime().ToString('o')})}
foreach($g in $valid|Group-Object MatchID,SnapshotTime,Market,Handicap){$market=$g.Group[0].Market;$actual=@($g.Group.Selection|Sort-Object -Unique);$expected=if($market-in@('SPF','RQSPF')){@('A','D','H')}elseif($market-eq'JQS'){@('0','1','2','3','4','5','6','7+')}elseif($market-eq'BQC'){@('AA','AD','AH','DA','DD','DH','HA','HD','HH')}else{$null};if($null-ne$expected-and(($actual-join'|')-ne(($expected|Sort-Object)-join'|'))){throw "Incomplete market snapshot: $($g.Name)"}}
$written=$false;if(-not$ValidateOnly){@($existing)+@($valid)|Export-Csv $dest -NoTypeInformation -Encoding UTF8;$written=$true};[pscustomobject]@{Status='VALID';Rows=$valid.Count;Groups=@($valid|Group-Object MatchID,SnapshotTime,Market,Handicap).Count;Written=$written;SourceHash=(Get-FileHash -LiteralPath $InputPath -Algorithm SHA256).Hash.ToLowerInvariant()}|ConvertTo-Json
